try {
  const cfg = $input.first().json;
  if (!cfg.apiKey) return [{ json: { error: 'N8N_API_KEY is empty' } }];
  const BASE = 'https://mmurawala.app.n8n.cloud/api/v1';
  const headers = { 'X-N8N-API-KEY': cfg.apiKey };

  // Step 1: Fetch registry
  let regResp;
  try {
    regResp = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/data-tables/8uXPK6pD52xG90Y0/rows?limit=250`, headers });
  } catch(e) {
    return [{ json: { step: 'fetch_registry', error: e.message } }];
  }
  const domains = (regResp.data || regResp || []).filter(r => String(r.enabled) === 'true');

  // Step 2: Fetch actions
  let allActions = [];
  try {
    let offset = 0;
    while (true) {
      const resp = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/data-tables/nTBOiE9byj3KcHVQ/rows?limit=250&offset=${offset}`, headers });
      const arr = Array.isArray(resp.data || resp) ? (resp.data || resp) : [];
      allActions = allActions.concat(arr);
      if (arr.length < 250) break;
      offset += 250;
    }
  } catch(e) {
    return [{ json: { step: 'fetch_actions', error: e.message } }];
  }
  const enabledActions = allActions.filter(a => String(a.enabled) === 'true');

  // Step 3: Build catalog (abbreviated for debug)
  const categoryMap = {};
  for (const d of domains) {
    const cat = (d.category || 'OTHER').toUpperCase();
    if (!categoryMap[cat]) categoryMap[cat] = [];
    const acts = enabledActions.filter(a => a.api_name === d.api_name).map(a => a.action).sort();
    if (acts.length > 0) categoryMap[cat].push(d.api_name + '(' + acts.join(',') + ')');
  }
  const ORDER = ['AI','CRM','PRODUCTIVITY','MARKETING','ANALYTICS','CMS','CREATIVE','DEPLOYMENT'];
  let catalog = "Execute any API action through the gateway. Input: domain (string), action (string), client (string - 'kahuna' or 'ascend'), params (object - action-specific parameters).\n\nAVAILABLE DOMAINS AND ACTIONS (call directly \u2014 no need for list_domains/list_actions/get_action_schema first):\n\n";
  for (const cat of ORDER) {
    if (categoryMap[cat] && categoryMap[cat].length > 0) {
      catalog += cat + ': ' + categoryMap[cat].join(' | ') + '\n\n';
      delete categoryMap[cat];
    }
  }
  for (const cat of Object.keys(categoryMap).sort()) {
    if (categoryMap[cat].length > 0) catalog += cat + ': ' + categoryMap[cat].join(' | ') + '\n\n';
  }
  catalog += "PARAM HINTS: For 'passthrough' domains (AI, Apollo, Gong, Semrush, Vercel, etc), params go directly as the API body. For 'handler' domains (HubSpot, Google, Slack, etc), check get_action_schema if unsure about required params.";

  // Step 4: GET workflow
  let wf;
  try {
    wf = await this.helpers.httpRequest({ method: 'GET', url: `${BASE}/workflows/42BsiQ2R7nstxydY`, headers });
  } catch(e) {
    return [{ json: { step: 'get_workflow', error: e.message } }];
  }

  // Step 5: Update description
  let found = false;
  for (const node of wf.nodes) {
    if (node.parameters && node.parameters.name === 'execute_action') {
      if (node.parameters.description === catalog) {
        return [{ json: { success: true, skipped: true, reason: 'unchanged', len: catalog.length } }];
      }
      node.parameters.description = catalog;
      found = true;
      break;
    }
  }
  if (!found) return [{ json: { step: 'find_node', error: 'not found' } }];

  // Step 6: PUT - with detailed error capture
  const putBody = { name: wf.name, nodes: wf.nodes, connections: wf.connections, settings: wf.settings };
  try {
    await this.helpers.httpRequest({
      method: 'PUT',
      url: `${BASE}/workflows/42BsiQ2R7nstxydY`,
      headers: { ...headers, 'Content-Type': 'application/json' },
      body: putBody
    });
  } catch(e) {
    return [{ json: { step: 'put_workflow', error: e.message, response: e.response ? JSON.stringify(e.response.data || e.response.body || '').substring(0, 500) : 'no response', body_keys: Object.keys(putBody), node_count: putBody.nodes.length, body_size: JSON.stringify(putBody).length } }];
  }

  return [{ json: { success: true, domains: domains.length, actions: enabledActions.length, catalog_length: catalog.length } }];
} catch (err) {
  return [{ json: { success: false, error: err.message, stack: String(err.stack).substring(0, 300) } }];
}
